rules.pseudocode:
max_dist = grid_width + grid_height - 2
for each action a in available_actions:
  if a == 'eat':
    if food_at_agent_position:
      a_imm = 1.0
      a_abs = 2.0 * (food.palatability - 0.1) / 0.9 - 1.0
    else:
      a_imm = 0.0
      a_abs = 0.0
  elif a == 'stay':
    a_imm = 0.0
    a_abs = 0.0
  else:  # movement action
    target_pos = position + direction_delta(a)
    nearest_food = find_nearest_food_from(target_pos, food_list)
    if nearest_food is not None:
      dist = manhattan_distance(target_pos, nearest_food)
      a_imm = 1.0 - dist / max_dist
      a_abs = 2.0 * (nearest_food.palatability - 0.1) / 0.9 - 1.0
    else:
      a_imm = 0.0
      a_abs = 0.0
